// mockSilenceManager is a mock implementation of SilenceManager for testing.
type mockSilenceManager struct {
	silences map[string]SilenceInput
	counter  int
}

// createSilence creates a silence and returns its ID.
func (m *mockSilenceManager) createSilence(s SilenceInput) (string, error) {
	if err := validateSilence(s); err != nil {
		return "", err
	}
	m.counter++
	id := generateSilenceID(m.counter)
	m.silences[id] = s
	return id, nil
}

// generateSilenceID generates a simple ID for testing purposes.
func generateSilenceID(counter int) string {
	return "silence-" + string(rune('a'+counter-1))
}

// validateSilence validates a silence input.
func validateSilence(s SilenceInput) error {
	if len(s.Matchers) == 0 {
		return NewErrorWithData("at least one matcher must be provided", nil)
	}
	if s.EndsAt.Before(s.StartsAt) {
		return NewErrorWithData("endsAt must be after startsAt", nil)
	}
	return nil
}

// NewErrorWithData creates a new error with data. This is a helper for testing.
// In the actual implementation, this would be an apiError.
func NewErrorWithData(msg string, data interface{}) error {
	return &apiError{errorBadData, nil}
}

